--SELECT DISTINCT 
--     PAT.PAT_MRN_ID             AS "MRN"
--    ,ORD_R.RESULT_DATE          AS "Result Date"
--    ,ORD_R.ORD_NUM_VALUE        AS "GLUCOSE"    
--    ,BMI."BMI"
--    ,BP."BP"
--    ,LIPID."LIPID"
--
--FROM ORDER_PROC ORD
--    LEFT JOIN ORDER_RESULTS        ORD_R ON ORD.ORDER_PROC_ID   = ORD_R.ORDER_PROC_ID
--    LEFT JOIN CLARITY_EAP            EAP ON ORD.PROC_ID         = EAP.PROC_ID
--    LEFT JOIN CLARITY_COMPONENT     COMP ON ORD_R.COMPONENT_ID  = COMP.COMPONENT_ID
--	LEFT JOIN ORDER_PROC_3           OR3 ON ORD.ORDER_PROC_ID   = OR3.ORDER_ID
--	LEFT JOIN ZC_ORDERING_MODE    ZC_ORD ON OR3.ORDERING_MODE_C = ZC_ORD.ORDERING_MODE_C
--	LEFT JOIN PATIENT                PAT ON ORD.PAT_ID          = PAT.PAT_ID
--	
--	LEFT JOIN BMI   ON BMI."MRN"    = PAT.PAT_MRN_ID
--	LEFT JOIN BP    ON BP."MRN"     = PAT.PAT_MRN_ID
--	LEFT JOIN LIPID ON LIPID."MRN"  = PAT.PAT_MRN_ID	
--	
--WHERE EAP.PROC_ID IN ('682','678') --CMP 682  --BMP 678
--    AND ORD_R.RESULT_STATUS_C = 3
--    AND ORD_R.ORD_NUM_VALUE IS NOT NULL
--    AND ORD_R.ORD_NUM_VALUE <> '9999999'
--    AND COMP.NAME LIKE '%GLUCOSE%'
--    AND ORD_R.RESULT_DATE >= '01-JAN-2023'  --EPIC_UTIL.EFN_DIN('{?Start Date}') -90
--    AND ORD_R.RESULT_DATE <= '01-JAN-2024' --EPIC_UTIL.EFN_DIN('{?End Date}')
--    AND ((ORD_R.RESULT_DATE - PAT.BIRTH_DATE)/365.242199) < 18
--    AND BMI."BMI" IS NOT NULL
--    AND BP."BP"   IS NOT NULL
--    AND LIPID."LIPID"   IS NOT NULL    
--   )

 SELECT DISTINCT 
  HSP_ACCOUNT.HSP_ACCOUNT_ID                                                    "HSP_ACCOUNT_ID"
 ,PATIENT.PAT_MRN_ID                                                            "MRN"
 ,HSP_ACCOUNT.PRIM_ENC_CSN_ID                                                   "CSN"
 ,0 AS                                                                          "ORDER_PROC_ID"
 ,MEDS."MED_BEGIN/ORDER_DATE"
 ,TRUNC((HSP_ACCOUNT.DISCH_DATE_TIME-PATIENT.BIRTH_DATE)/365.242199)            "AGE_AT_ENC"
 ,HSP_ACCOUNT.HSP_ACCOUNT_NAME                                                  "ACCOUNT_NAME"
 ,ZC_ACCT_BASECLS_HA.NAME                                                       "ACCOUNT_BASECLASS"
 ,ZC_ACCT_CLASS_HA.NAME                                                         "ACCOUNT_CLASS"
 ,HSP_ACCOUNT.ADM_DATE_TIME                                                     "ADM_DATE_TIME"
 ,HSP_ACCOUNT.DISCH_DATE_TIME                                                   "DISCH_DATE_TIME"
 ,COALESCE(SER.PROV_NAME,ser2.PROV_NAME)                                        "PROV_NAME"
 ,SER.PROV_NAME as "attending provider"
,SER2.PROV_NAME as "admitting provider"
,SER3.PROV_NAME as "discharging provider"
 ,'NON-IP' AS                                                                   "IP_CONSULT_PROV"
 ,CLARITY_LOC.LOC_NAME                                                          "LOC_NAME"
 ,'NON-ED' AS                                                                   "ADMIT_DEPT"
 ,CLARITY_DEP.DEPARTMENT_NAME                                                   "DISCH_DEPARTMENT"
 --,CTE2."DX_NAME(S)"
 --,CTE2."ICD-10 CODE"
 ,CASE WHEN ZC_ACCT_BASECLS_HA.NAME = 'Inpatient' THEN 'Inpatient' ELSE 'Outpatient' END AS "INP/OUTPT"
 
 FROM CTE2
 INNER JOIN HSP_ACCOUNT         ON CTE2.HSP_ACCOUNT_ID              = HSP_ACCOUNT.HSP_ACCOUNT_ID
 INNER JOIN CLARITY_LOC         ON HSP_ACCOUNT.DISCH_LOC_ID         = CLARITY_LOC.LOC_ID
 LEFT JOIN CLARITY_DEP          ON HSP_ACCOUNT.DISCH_DEPT_ID        = CLARITY_DEP.DEPARTMENT_ID
 LEFT JOIN CLARITY_DEP     DEP2 ON HSP_ACCOUNT.ADM_DEPARMENT_ID     = DEP2.DEPARTMENT_ID
 LEFT JOIN ZC_ACCT_CLASS_HA     ON HSP_ACCOUNT.ACCT_CLASS_HA_C      = ZC_ACCT_CLASS_HA.ACCT_CLASS_HA_C 
 LEFT JOIN ZC_ACCT_BASECLS_HA   ON HSP_ACCOUNT.ACCT_BASECLS_HA_C    = ZC_ACCT_BASECLS_HA.ACCT_BASECLS_HA_C
 INNER JOIN V_PAT_FACT          ON HSP_ACCOUNT.PAT_ID               = V_PAT_FACT.PAT_ID 
 INNER JOIN PATIENT             ON HSP_ACCOUNT.PAT_ID               = PATIENT.PAT_ID 
 LEFT JOIN CLARITY_SER      SER ON HSP_ACCOUNT.ATTENDING_PROV_ID    = SER.PROV_ID
 LEFT JOIN CLARITY_SER     SER2 ON HSP_ACCOUNT.ADM_PROV_ID          = SER2.PROV_ID
 LEFT JOIN HSP_ATND_PROV   ATND ON HSP_ACCOUNT.PRIM_ENC_CSN_ID      = ATND.PAT_ENC_CSN_ID 
 LEFT JOIN CLARITY_SER     SER3 ON ATND.PROV_ID                     = SER3.PROV_ID
 
INNER JOIN MEDS ON MEDS."MRN" = PATIENT.PAT_MRN_ID  
--INNER JOIN LABS ON LABS."MRN" = PAT.PAT_MRN_ID   

WHERE 1=1

    AND TRUNC((HSP_ACCOUNT.DISCH_DATE_TIME-PATIENT.BIRTH_DATE)/365.242199) < 18
    AND HSP_ACCOUNT.LOC_ID = '100000'  
    AND (
        SER.PROV_ID IN ('161930','454480','472685','476801','23510','483603','13325','458790','479858','144944','149584','488681','36839','488209','480027','480028','470637','480029','487905','144791','473430','477091','10529','473474', '143598','27772','157017','138508','25312','27094','145072','136584','33168','452487','10518','10616','36765','34087','124791','482023')
    OR SER2.PROV_ID IN ('161930','454480','472685','476801','23510','483603','13325','458790','479858','144944','149584','488681','36839','488209','480027','480028','470637','480029','487905','144791','473430','477091','10529','473474', '143598','27772','157017','138508','25312','27094','145072','136584','33168','452487','10518','10616','36765','34087','124791','482023')
    OR SER3.PROV_ID IN ('161930','454480','472685','476801','23510','483603','13325','458790','479858','144944','149584','488681','36839','488209','480027','480028','470637','480029','487905','144791','473430','477091','10529','473474', '143598','27772','157017','138508','25312','27094','145072','136584','33168','452487','10518','10616','36765','34087','124791','482023')
        )
    AND (
    CLARITY_DEP.DEPARTMENT_ID IN (    1000107005,    1000102049,    1000104017,    1015101044,    1005001013,    1000201007,    1000201002,    1000104093,    1000102046,
    1000102011,    10501122,    10302007,    1000104002,    1000104014,    1000104037,    1000104043,    1000104066,    1000116030,    1009801001,    1009801002,    1009801003,
    1035601001,    1000102013,    1004801001,    1009301027,    1000100010,    1012301026,    1008301084,    1009301001,    1001601031,    1000104092,    1000102057,    1000201010     )
    OR DEP2.DEPARTMENT_ID IN (    1000107005,    1000102049,    1000104017,    1015101044,    1005001013,    1000201007,    1000201002,    1000104093,    1000102046,
    1000102011,    10501122,    10302007,    1000104002,    1000104014,    1000104037,    1000104043,    1000104066,    1000116030,    1009801001,    1009801002,    1009801003,
    1035601001,    1000102013,    1004801001,    1009301027,    1000100010,    1012301026,    1008301084,    1009301001,    1001601031,    1000104092,    1000102057,    1000201010     )
    )
ORDER BY 
  CLARITY_LOC.LOC_NAME
 ,CLARITY_DEP.DEPARTMENT_NAME

 ))
 
 
