, MEDS as (
select distinct * from (
SELECT DISTINCT
     PAT.PAT_MRN_ID                                     AS "MRN"
    ,PAT.PAT_NAME                                       AS "PATIENT"
    ,MED.PAT_ENC_CSN_ID                                 AS "CSN"
    ,ENC.CONTACT_DATE                                   AS "CONTACT_DATE"
    ,MED.ORDERING_DATE                                  as "MED_BEGIN/ORDER_DATE"    
    ,MED.ORDERING_DATE                                  AS "ORDER_DATE"
    ,SER.PROV_NAME                                      AS "AUTH_PROVIDER"
    ,CMED.NAME                                          AS "MEDICATION"
    ,TRUNC((MED.ORDER_INST-PAT.BIRTH_DATE)/365.242199)  AS "PATIENT_AGE"
    ,MEDX.TAKING_YN                                     AS "CURRENTLY_TAKING?"
    ,'Outpatient'                                       AS "IN_OR_OUT?" 
    
FROM            
                ORDER_MED MED 
    LEFT JOIN  GROUPER_MED_RECS   RECS ON MED.MEDICATION_ID        = RECS.EXP_MEDS_LIST_ID     
    LEFT JOIN  GROUPER_ITEMS       GRP ON RECS.GROUPER_ID          = GRP.GROUPER_ID            
    LEFT JOIN  CLARITY_MEDICATION CMED ON MED.MEDICATION_ID        = CMED.MEDICATION_ID       
    LEFT JOIN  CLARITY_SER         SER ON MED.AUTHRZING_PROV_ID    = SER.PROV_ID
    LEFT JOIN  ZC_ORDER_CLASS      ZCO ON MED.ORDER_CLASS_C        = ZCO.ORDER_CLASS_C
    LEFT JOIN  ZC_ORDER_STATUS     ZCS ON MED.ORDER_STATUS_C       = ZCS.ORDER_STATUS_C
    LEFT JOIN  ZC_RSN_FOR_DISCON   ZCR ON MED.RSN_FOR_DISCON_C     = ZCR.RSN_FOR_DISCON_C    
    LEFT JOIN  PATIENT             PAT ON MED.PAT_ID               = PAT.PAT_ID
    LEFT JOIN  PAT_ENC             ENC ON MED.PAT_ENC_CSN_ID       = ENC.PAT_ENC_CSN_ID
    LEFT JOIN  MEDS_REV_HX_LIST   MEDX ON MED.ORDER_MED_ID         = MEDX.MEDICATION_ORDER_ID        
    
WHERE 
        ENC.CONTACT_DATE  >= '01-JAN-2023' 
    AND ENC.CONTACT_DATE  <  '01-JAN-2024'
    AND TRUNC((MED.ORDER_INST-PAT.BIRTH_DATE)/365.242199) < 18
    AND GRP.GROUPER_ID IN ('5431100420','2100000842','2100000601','119613','106060','107472','110472','113623','117473','120930','123997','112234','115750')      
    AND MED.ORDERING_MODE_C = 1                                                 --OUTPATIENT
    AND MED.ORDER_CLASS_C IN ('1','9','12') --,'3','45','10')  
    --AND MEDX.TAKING_YN = 'Y'
    AND (MED.RSN_FOR_DISCON_C IS NULL OR MED.RSN_FOR_DISCON_C IN ('12','5','14','96')) 
    )
    
    union all
    
    select distinct * from (
    SELECT DISTINCT
     PAT.PAT_MRN_ID                                                               AS "MRN"
    ,PAT.PAT_NAME                                                                 AS "PATIENT"   
    ,OM.PAT_ENC_CSN_ID                                                            AS "CSN"
    ,MIF.SCHEDULED_TIME                                                           AS "SCHED_DATE"
    ,MIF.TAKEN_TIME                                                               as "MED_BEGIN/ORDER_DATE"
    ,MIF.TAKEN_TIME                                                               AS "TAKEN_DATE"
    ,TAKEN.NAME                                                                   AS "PROVIDER"
    ,MED.NAME                                                                     AS "MEDICATION"
    ,TRUNC((MIF.TAKEN_TIME-PAT.BIRTH_DATE)/365.242199)                            AS "PATIENT_AGE"
    ,CASE WHEN ZCM.NAME IN ('Given','Bolus from Bag','New Bag','Patch Applied','Rate Changed','Rate Maintained','Rate Verify','Restarted') THEN 'Y' ELSE 'N' END AS "CURRENTLY TAKING?"
    ,'Inpatient'                                                                  AS "IN_OR_OUT?"  

FROM 
            MAR_ADMIN_INFO     MIF
  LEFT JOIN ORDER_MED           OM ON MIF.ORDER_MED_ID      = OM.ORDER_MED_ID
  LEFT JOIN CLARITY_MEDICATION MED ON OM.MEDICATION_ID      = MED.MEDICATION_ID
  LEFT JOIN ZC_MAR_RSLT        ZCM ON MIF.MAR_ACTION_C      = ZCM.RESULT_C
  LEFT JOIN CLARITY_EMP      TAKEN ON MIF.USER_ID           = TAKEN.USER_ID
  LEFT JOIN CLARITY_EMP        DOC ON MIF.MAR_DOC_USER_ID   = DOC.USER_ID
  LEFT JOIN  PATIENT           PAT ON OM.PAT_ID             = PAT.PAT_ID
  LEFT JOIN  GROUPER_MED_RECS RECS ON OM.MEDICATION_ID      = RECS.EXP_MEDS_LIST_ID     
  LEFT JOIN  GROUPER_ITEMS     GRP ON RECS.GROUPER_ID       = GRP.GROUPER_ID    
     
WHERE
      MIF.TAKEN_TIME >= '01-JAN-2023' 
  AND MIF.TAKEN_TIME <  '01-JAN-2024'
  AND TRUNC((MIF.TAKEN_TIME-PAT.BIRTH_DATE)/365.242199) < 18
    AND GRP.GROUPER_ID IN ('5431100420','2100000842','2100000601','119613','106060','107472','110472','113623','117473','120930','123997','112234','115750')
  AND ZCM.NAME IN ('Given','Bolus from Bag','New Bag','Patch Applied','Rate Changed','Rate Maintained','Rate Verify','Restarted')
  )
  )

