--FROM ORDER_PROC ORD
--    LEFT JOIN ORDER_RESULTS        ORD_R ON ORD.ORDER_PROC_ID   = ORD_R.ORDER_PROC_ID
--    LEFT JOIN CLARITY_EAP            EAP ON ORD.PROC_ID         = EAP.PROC_ID
--    LEFT JOIN CLARITY_COMPONENT     COMP ON ORD_R.COMPONENT_ID  = COMP.COMPONENT_ID
--	LEFT JOIN ORDER_PROC_3           OR3 ON ORD.ORDER_PROC_ID   = OR3.ORDER_ID
--	LEFT JOIN ZC_ORDERING_MODE    ZC_ORD ON OR3.ORDERING_MODE_C = ZC_ORD.ORDERING_MODE_C
--	LEFT JOIN PATIENT                PAT ON ORD.PAT_ID          = PAT.PAT_ID
--	
--	LEFT JOIN BMI   ON BMI."MRN"    = PAT.PAT_MRN_ID
--	LEFT JOIN BP    ON BP."MRN"     = PAT.PAT_MRN_ID
--	LEFT JOIN LIPID ON LIPID."MRN"  = PAT.PAT_MRN_ID	
--	
--WHERE EAP.PROC_ID IN ('682','678') --CMP 682  --BMP 678
--    AND ORD_R.RESULT_STATUS_C = 3
--    AND ORD_R.ORD_NUM_VALUE IS NOT NULL
--    AND ORD_R.ORD_NUM_VALUE <> '9999999'
--    AND COMP.NAME LIKE '%GLUCOSE%'
--    AND ORD_R.RESULT_DATE >= '01-JAN-2023'  --EPIC_UTIL.EFN_DIN('{?Start Date}') -90
--    AND ORD_R.RESULT_DATE <= '01-JAN-2024' --EPIC_UTIL.EFN_DIN('{?End Date}')
--    AND ((ORD_R.RESULT_DATE - PAT.BIRTH_DATE)/365.242199) < 18
--    AND BMI."BMI" IS NOT NULL
--    AND BP."BP"   IS NOT NULL
--    AND LIPID."LIPID"   IS NOT NULL    
--   )

SELECT DISTINCT 
HSP.HSP_ACCOUNT_ID                                                              "HSP_ACCOUNT_ID",
PAT.PAT_MRN_ID                                                                  "MRN",
ED.PAT_ENC_CSN_ID                                                               "CSN",
ORD.ORDER_PROC_ID                                                               "ORDER_PROC_ID",
MEDS."MED_BEGIN/ORDER_DATE",
TRUNC((HSP.DISCH_DATE_TIME-PAT.BIRTH_DATE)/365.242199)                          "AGE_AT_ENC",
HSP.HSP_ACCOUNT_NAME                                                            "ACCOUNT_NAME",
ZC_ACCT_BASECLS_HA.NAME                                                         "ACCOUNT_BASECLASS",
ZC_ACCT_CLASS_HA.NAME                                                           "ACCOUNT_CLASS",
HSP.ADM_DATE_TIME                                                               "ADM_DATE_TIME",
HSP.DISCH_DATE_TIME                                                             "DISCH_DATE_TIME",
COALESCE(SER3.PROV_NAME,SER2.PROV_NAME,SER.PROV_NAME) AS                        "PROV_NAME",
SER.PROV_NAME as "attending provider",
SER2.PROV_NAME as "admitting provider",
SER3.PROV_NAME as "attend list provider",
SER4.PROV_NAME AS "IP PSYCH CONSULT provider"  ,                                                           -- "IP_CONSULT_PROV",
LOC.LOC_NAME                                                                    "LOC_NAME",
ADM.DEPARTMENT_NAME                                                             "ADMIT_DEPARTMENT",
DEP.DEPARTMENT_NAME                                                             "DISCH_DEPARTMENT",
--CTE2."DX_NAME(S)",
--CTE2."ICD-10 CODE",
CASE WHEN ZC_ACCT_BASECLS_HA.NAME = 'Inpatient' then 'Inpatient' else 'Outpatient' end as "INP/OUTPT"

FROM ORDER_PROC ORD  
LEFT JOIN CLARITY_EAP       EAP ON EAP.PROC_ID              = ORD.PROC_ID
LEFT JOIN PATIENT           PAT ON ORD.PAT_ID               = PAT.PAT_ID
INNER JOIN F_ED_ENCOUNTERS   ED ON ED.PAT_ENC_CSN_ID        = ORD.PAT_ENC_CSN_ID
LEFT JOIN HSP_ACCOUNT      HSP ON ED.HOSPITAL_ACCOUNT_ID   = HSP.HSP_ACCOUNT_ID  
INNER JOIN CTE2                 ON ED.HOSPITAL_ACCOUNT_ID   = CTE2.HSP_ACCOUNT_ID
LEFT JOIN ZC_ACCT_CLASS_HA      ON HSP.ACCT_CLASS_HA_C      = ZC_ACCT_CLASS_HA.ACCT_CLASS_HA_C 
LEFT JOIN ZC_ACCT_BASECLS_HA    ON HSP.ACCT_BASECLS_HA_C    = ZC_ACCT_BASECLS_HA.ACCT_BASECLS_HA_C
LEFT JOIN CLARITY_LOC       LOC ON HSP.DISCH_LOC_ID         = LOC.LOC_ID
LEFT JOIN CLARITY_DEP       DEP ON HSP.DISCH_DEPT_ID        = DEP.DEPARTMENT_ID
LEFT JOIN CLARITY_DEP       ADM ON HSP.ADM_DEPARMENT_ID     = ADM.DEPARTMENT_ID
LEFT JOIN HSP_ATND_PROV    ATND ON HSP.PRIM_ENC_CSN_ID      = ATND.PAT_ENC_CSN_ID 
 
LEFT JOIN CLARITY_SER       SER ON HSP.ATTENDING_PROV_ID    = SER.PROV_ID and HSP.ATTENDING_PROV_ID IN ('161930','454480','472685','476801','23510','483603','13325','458790','479858','144944','149584','488681','36839','488209','480027','480028','470637','480029','487905','144791','473430','477091','10529','473474', '143598','27772','157017','138508','25312','27094','145072','136584','33168','452487','10518','10616','36765','34087','124791','482023')
LEFT JOIN CLARITY_SER      SER2 ON HSP.ADM_PROV_ID          = SER2.PROV_ID and HSP.ADM_PROV_ID      IN ('161930','454480','472685','476801','23510','483603','13325','458790','479858','144944','149584','488681','36839','488209','480027','480028','470637','480029','487905','144791','473430','477091','10529','473474', '143598','27772','157017','138508','25312','27094','145072','136584','33168','452487','10518','10616','36765','34087','124791','482023')
LEFT JOIN CLARITY_SER      SER3 ON ATND.PROV_ID             = SER3.PROV_ID and ATND.PROV_ID         IN ('161930','454480','472685','476801','23510','483603','13325','458790','479858','144944','149584','488681','36839','488209','480027','480028','470637','480029','487905','144791','473430','477091','10529','473474', '143598','27772','157017','138508','25312','27094','145072','136584','33168','452487','10518','10616','36765','34087','124791','482023')

INNER JOIN ORDER_PROC_3         OR3 ON ORD.ORDER_PROC_ID    = OR3.ORDER_ID
LEFT JOIN CLARITY_SER          SER4 ON OR3.STAT_COMP_USER_ID= SER4.USER_ID and SER4.PROV_ID         IN ('161930','454480','472685','476801','23510','483603','13325','458790','479858','144944','149584','488681','36839','488209','480027','480028','470637','480029','487905','144791','473430','477091','10529','473474', '143598','27772','157017','138508','25312','27094','145072','136584','33168','452487','10518','10616','36765','34087','124791','482023')
LEFT JOIN V_CUBE_D_PROVIDER   VCUBE ON SER4.PROV_ID         = VCUBE.PROVIDER_ID

INNER JOIN MEDS ON MEDS."MRN" = PAT.PAT_MRN_ID  
--INNER JOIN LABS ON LABS."MRN" = PAT.PAT_MRN_ID  

 left join zc_reason_for_canc zcc on ord.REASON_FOR_CANC_C = zcc.REASON_FOR_CANC_C
 left join zc_order_status zco on ord.order_status_c = zco.order_status_c  
  
WHERE 
ORD.PROC_ID IN (148216,375,423,355,989890,989891) 
AND TRUNC((HSP.DISCH_DATE_TIME-PAT.BIRTH_DATE)/365.242199) < 18
AND ORD.INSTANTIATED_TIME IS NOT NULL
AND ORD.ORDER_STATUS_C = 5
AND (ord.REASON_FOR_CANC_C IS NULL or zcc.name = 'Patient Discharge')
AND ED.FIRST_EMERGENCY_DEPARTMENT_ID = 1000100010
AND (
        SER.PROV_ID IN ('161930','454480','472685','476801','23510','483603','13325','458790','479858','144944','149584','488681','36839','488209','480027','480028','470637','480029','487905','144791','473430','477091','10529','473474', '143598','27772','157017','138508','25312','27094','145072','136584','33168','452487','10518','10616','36765','34087','124791','482023')
    OR SER2.PROV_ID IN ('161930','454480','472685','476801','23510','483603','13325','458790','479858','144944','149584','488681','36839','488209','480027','480028','470637','480029','487905','144791','473430','477091','10529','473474', '143598','27772','157017','138508','25312','27094','145072','136584','33168','452487','10518','10616','36765','34087','124791','482023')
    OR SER3.PROV_ID IN ('161930','454480','472685','476801','23510','483603','13325','458790','479858','144944','149584','488681','36839','488209','480027','480028','470637','480029','487905','144791','473430','477091','10529','473474', '143598','27772','157017','138508','25312','27094','145072','136584','33168','452487','10518','10616','36765','34087','124791','482023')
    OR SER4.PROV_ID IN ('161930','454480','472685','476801','23510','483603','13325','458790','479858','144944','149584','488681','36839','488209','480027','480028','470637','480029','487905','144791','473430','477091','10529','473474', '143598','27772','157017','138508','25312','27094','145072','136584','33168','452487','10518','10616','36765','34087','124791','482023')
        )

ORDER BY 
  LOC.LOC_NAME
 ,DEP.DEPARTMENT_NAME
 
 )
 )
 )